def mystery(x):
    if not isinstance(x, int) or x <= 1:
        return False

    def is_happy(n):
        seen = set()
        while n != 1 and n not in seen:
            seen.add(n)
            n = sum(int(digit) ** 2 for digit in str(n))
        return n == 1

    return is_happy(x)
```

